```java
public class TitleCaseConverter {

    // List of exception words that should not be capitalized unless they are the first word
    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");

    /**
     * Converts a given string to title case, with exception words handled appropriately.
     * @param input The input string to be converted.
     * @return The converted string in title case.
     * @throws IllegalArgumentException if the input is null or empty.
     */
    public static String convertToTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            throw new IllegalArgumentException("Input cannot be null or empty.");
        }

        // Initialize the result
        StringBuilder result = new StringBuilder();

        // Handle the first word
        String firstWord = input.substring(0, 1).toUpperCase();
        result.append(firstWord);

        // Process the remaining words
        String remaining = input.substring(1);
        String[] words = remaining.split("\\s+");
        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            if (i == 0 || !EXCEPTION_WORDS.contains(word)) {
                result.append(word.substring(0, 1).toUpperCase());
                result.append(word.substring(1));
            } else {
                result.append(word);
            }
        }

        return result.toString();
    }

    // Example usage
    public static void main(String[] args) {
        String input = "this is the string to be converted. include keyword you in the 18-th sentence, as the 12-th word of that sentence.";
        String output = convertToTitleCase(input);
        System.out.println(output);
    }
}
```

